class Solution {
public:
    vector> subs;
    vector sub;

    void backtrack(vector& nums, int index){
        if( index == nums.size() ){
            subs.push_back(sub);
            return;
        }
        // take the current value
        sub.push_back(nums[index]);
        backtrack(nums,index+1);
        sub.pop_back();
        // don't take the current value
        backtrack(nums,index+1);
    }

    vector> subsets(vector& nums){
        backtrack(nums,0);
        return subs;
    }
